// inngest-fn/functions/sendDailyDigest.tsx
var sendDailyDigest = inngest.createFunction(
  {
    id: "daily-weather-digest",
    name: "Daily Weather Digest",
    triggers: [{ cron: "8 0 * * *" }]
  },
  async () => {
    const groups = await getGroupedSubscribers();
    let sent = 0;
    let failed = 0;
    let total = 0;
    for (const group of groups) {
      total += group.subscribers.length;
      let weather;
      try {
        weather = await getWeatherByCoord_default(group.lat, group.lon);
      } catch (err) {
        console.error(`Weather fetch failed for (${group.lat}, ${group.lon}):`, err);
        failed += group.subscribers.length;
        continue;
      }
      const html = await render2(
        /* @__PURE__ */ React17.createElement(WeatherDigest, { weather })
      );
      const emailResults = await Promise.allSettled(
        group.subscribers.map(
          (sub) => sendEmail({
            to: sub.email,
            subject: `Today's weather in ${weather.location.city} \u{1F324}\uFE0F`,
            html: html.replace(
              "__UNSUBSCRIBE_URL__",
              `${process.env.APP_URL}/unsubscribe?email=${encodeURIComponent(sub.email)}`
            )
          })
        )
      );
      for (const result of emailResults) {
        if (result.status === "fulfilled") {
          sent++;
        } else {
          failed++;
          console.error("Email failed:", result.reason);
        }
      }
    }
    return { sent, failed, total, uniqueLocations: groups.length };
  }
);

